-- =====================================================================
-- Deepholm Downport  --  24  Server-side spell_dbc (REQUIRED)
-- ---------------------------------------------------------------------
-- This fork's worldserver loads spells from acore_world.spell_dbc (a 234-col
-- runtime table), NOT just the client Spell.dbc. The Spell.csv additions (19/22)
-- only give the CLIENT tooltips/visuals -- without these rows the server cannot
-- cast/resolve the Deepholm spells (Xariona kit, Twilight Buffet, credit triggers).
-- Same 3.3.5 layout as Spell.csv + the 2 unk_320 stance-mask high-words (=0).
-- 35 spells = the 12 in 19_spell_dbc_additions + the 23 in 22_credit_spell_dbc_additions.
-- =====================================================================

DELETE FROM `spell_dbc` WHERE `ID` IN (93544,93545,93546,93553,93554,93556,95385,93425,100168,84069,84153,83483,70354,81535,82141,82143,82145,82147,82149,82152,82154,82156,82159,82161,82669,82747,82773,82845,82849,84436,84499,84837,86610,86639,86717);

